<script>
  // Manejador global para confirmaciones. Intercepta clicks en enlaces
  // que usen el atributo `data-href` o `data-confirm` y muestra SweetAlert2.
  $(document).on('click', 'a[data-href], a[data-confirm]', function(e) {
    var $el = $(this);
    var href = $el.data('href') || $el.attr('href');
    var title = $el.data('confirm-title') || 'Confirmación';
    var text = $el.data('confirm') || '¿Desea eliminar este registro?';

    // Si el enlace no tiene data-href y su href apunta a un anchor, permitir comportamiento normal
    if (!href || href === '#') {
      e.preventDefault();
    } else {
      e.preventDefault();
    }

    Swal.fire({
      title: title,
      text: text,
      icon: 'error',
      showCancelButton: true,
      confirmButtonColor: 'rgba(218, 29, 29, 1)',
      cancelButtonColor: '#3085d6',
      confirmButtonText: 'Sí',
      cancelButtonText: 'No'
    }).then((result) => {
      if (result.isConfirmed) {
        // Si hay una URL válida la navegamos (GET)
        if (href && href !== '#') {
          window.location.href = href;
        } else if ($el.data('method') && $el.data('method').toLowerCase() === 'post') {
          // Si se requiere POST creamos y enviamos un formulario
          var form = $('<form>', {
            method: 'POST',
            action: $el.data('href')
          });
          // Intentar agregar token CSRF si existe en meta
          var token = $('meta[name="csrf-token"]').attr('content');
          if (token) {
            form.append($('<input>', {
              type: 'hidden',
              name: '_token',
              value: token
            }));
          }
          $('body').append(form);
          form.submit();
        }
      }
    });
  });
</script>

